// Build the complete Meta Cloud API payload here as a JS object so
// the HTTP node only needs JSON.stringify($json.payload). Same pattern
// as the daily-prep workflow — see that file for the full rationale.

const data = $input.first().json;

const safe = (s) => {
  if (s === undefined || s === null) return '无';
  const str = String(s)
    .replace(/\n/g, ' / ')
    .replace(/\t/g, ' ')
    .replace(/\s{5,}/g, '    ')
    .trim();
  return str.length > 0 ? str : '无';
};

// Owner's own number — this push is for the boss, not BowlMama.
const RECIPIENT = '60165119118';

const payload = {
  messaging_product: 'whatsapp',
  to: RECIPIENT,
  type: 'template',
  template: {
    name: 'daily_recap_boss',
    language: { code: 'zh_CN' },
    components: [
      {
        type: 'body',
        parameters: [
          { type: 'text', text: safe(data.today) },
          { type: 'text', text: safe(data.todaySummary) },
          { type: 'text', text: safe(data.voucherSalesSummary) },
          { type: 'text', text: safe(data.customerSummary) },
          { type: 'text', text: safe(data.tomorrowSummary) },
          { type: 'text', text: safe(data.tomorrowCriticalNotesText) },
        ],
      },
    ],
  },
};

return [{ json: { payload, _raw: data } }];

// Surface failures clearly. Replace this with a Slack/Email node
// hooked to your own number if you want push notifications on failure.
const err = $input.first().json;
console.error('[daily-recap] WhatsApp send failed', JSON.stringify(err));
return [{ json: { error: err } }];
